    if l_order_id is not None:
        values = l_order_id.split(',')
        values = [int(val) for val in values]
        set_items['order_id'] = values
            
    
    
    order_items = dict()
    if order_by is not None:
        orders = order_by.split(',')
        for order in orders:
            if order.startswith('-'):
                order_items[order[1:]] = 'desc'
            else:
                order_items[order] = 'asc'
    data = d_db.filter_bigorder_two(items, search_items, set_items, order_items, page, page_size)
    c = d_db.filter_count_bigorder_two(items, search_items, set_items)
    
    return FilterResBigorderTwo(data=data, total=c)


