@router.post(f'/business_license/create', response_model=SBusinessLicense)
async def create_business_license(item: CreateBusinessLicense) -> SBusinessLicense:
    dict_item = dict(item)
    for k,v in dict_item.items():
        if v is not None:
            v = str(v)
            v = v.replace(" ", "")
            get_search = re.search(r"'", v, flags=0)
            get_search2 = re.search(r'%27', v, flags=0)
            get_search3 = re.search(r'unionselect', v, flags=0)
            if get_search or get_search2 or get_search3:
               raise HTTPException(status_code=404, detail='bad way~~~~~~')

    return d_db.insert_business_license(item)
        
    
@router.post(f'/business_license/update', response_model=str)
async def update_business_license(item: SBusinessLicense) -> str:
    d_db.update_business_license(item)
    return "success"

    
@router.get(f'/business_license/get', response_model=SBusinessLicense)
async def get_business_license(business_license_id: int) -> SBusinessLicense:
    return d_db.get_business_license(business_license_id)


