@router.post(f'/sd_guest/create', response_model=SSdGuest)
async def create_sd_guest(item: CreateSdGuest) -> SSdGuest:
    dict_item = dict(item)
    for k,v in dict_item.items():
        if v is not None:
            v = str(v)
            v = v.replace(" ", "")
            get_search = re.search(r"'", v, flags=0)
            get_search2 = re.search(r'%27', v, flags=0)
            get_search3 = re.search(r'unionselect', v, flags=0)
            if get_search or get_search2 or get_search3:
               raise HTTPException(status_code=404, detail='bad way~~~~~~')

    return d_db.insert_sd_guest(item)
        
    
@router.post(f'/sd_guest/update', response_model=str)
async def update_sd_guest(item: SSdGuest) -> str:
    d_db.update_sd_guest(item)
    return "success"

    
