@router.get(f'/sh_userlevel/filter', response_model=FilterResShUserlevel)
async def filter_sh_userlevel(
        id: Optional[str] = None, 
        register_time: Optional[str] = None, 
        level_name: Optional[str] = None, 
        propo: Optional[str] = None, 
        shop_id: Optional[str] = None, 
        pinpai_id: Optional[str] = None, 
        status: Optional[str] = None, 
        l_id: Optional[str] = None, 
        l_register_time: Optional[str] = None, 
        l_level_name: Optional[str] = None, 
        l_propo: Optional[str] = None, 
        l_shop_id: Optional[str] = None, 
        l_pinpai_id: Optional[str] = None, 
        l_status: Optional[str] = None, 
        s_level_name: Optional[str] = None,
        order_by: Optional[str] = None,
        page: int = 1, 
        page_size: int = 20) -> FilterResShUserlevel:

    """
    1. 按照字段查询`?field1=value1&field2=value2`
    2. 按照范围查询，大于某个值`?field=value,`, 表示filed大于value
    3. 按照范围查询，小于某个值`?field=,value`， 表示field小于value
    4. 按照范围查询，范围值`?field=value1,value2`，表示搜索field大于等于value1，小于等于value2
    5. page是页数，第一页为1
    6. page_size为每一页大小， 默认20
    7. 如果是日期，请使用时间戳，十位的时间戳，单位：秒
    8. 所有字符串字段均可搜索，需要在字段前加个前缀`s_`,例如搜索`username`包含`zhang`， 则可以这样`s_username=zhang`写,这里只是一个假设
    9. 字段的多选择（in关系），需要在字段前加前缀`l_`,并且以逗号`,`隔开,例如要找出`id=2`或者`id=3`的样本，可以这样写`?l_id=2,3`
    """
    

    items = dict()
    search_items = dict()
    set_items = dict()

    if id is not None:
        values = id.split(',')
        if len(values) == 1:
            val = values[0]
            items['id'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['id_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['id_end'] = int(val)
        
    if register_time is not None:
        values = register_time.split(',')
        if len(values) == 1:
            val = values[0]
            items['register_time'] = datetime.fromtimestamp(int(val))
        else:
            val = values[0]
            if val != '':
                items['register_time_start'] = datetime.fromtimestamp(int(val))
            
            val = values[1]
            if val != '':
                items['register_time_end'] = datetime.fromtimestamp(int(val))
        
    if level_name is not None:
        values = level_name.split(',')
        if len(values) == 1:
            val = values[0]
            items['level_name'] = val
        else:
            val = values[0]
            if val != '':
                items['level_name_start'] = val
            
            val = values[1]
            if val != '':
                items['level_name_end'] = val
        
    if propo is not None:
        values = propo.split(',')
        if len(values) == 1:
            val = values[0]
            items['propo'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['propo_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['propo_end'] = int(val)
        
    if shop_id is not None:
        values = shop_id.split(',')
        if len(values) == 1:
            val = values[0]
            items['shop_id'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['shop_id_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['shop_id_end'] = int(val)
        
    if pinpai_id is not None:
        values = pinpai_id.split(',')
        if len(values) == 1:
            val = values[0]
            items['pinpai_id'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['pinpai_id_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['pinpai_id_end'] = int(val)
        
    if status is not None:
        values = status.split(',')
        if len(values) == 1:
            val = values[0]
            items['status'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['status_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['status_end'] = int(val)
        

    if s_level_name is not None:
        search_items['level_name'] = '%' + s_level_name + '%'
        

    if l_id is not None:
        values = l_id.split(',')
        values = [int(val) for val in values]
        set_items['id'] = values
        
    if l_register_time is not None:
        values = l_register_time.split(',')
        values = [datetime.fromtimestamp(int(val)) for val in values]
        set_items['register_time'] = values
        
    if l_level_name is not None:
        values = l_level_name.split(',')
        values = [val for val in values]
        set_items['level_name'] = values
        
    if l_propo is not None:
        values = l_propo.split(',')
        values = [int(val) for val in values]
        set_items['propo'] = values
        
    if l_shop_id is not None:
        values = l_shop_id.split(',')
        values = [int(val) for val in values]
        set_items['shop_id'] = values
        
    if l_pinpai_id is not None:
        values = l_pinpai_id.split(',')
        values = [int(val) for val in values]
        set_items['pinpai_id'] = values
        
    if l_status is not None:
        values = l_status.split(',')
        values = [int(val) for val in values]
        set_items['status'] = values
            
    
    
    order_items = dict()
    if order_by is not None:
        orders = order_by.split(',')
        for order in orders:
            if order.startswith('-'):
                order_items[order[1:]] = 'desc'
            else:
                order_items[order] = 'asc'
    data = d_db.filter_sh_userlevel(items, search_items, set_items, order_items, page, page_size)
    c = d_db.filter_count_sh_userlevel(items, search_items, set_items)
    
    return FilterResShUserlevel(data=data, total=c)


