@router.post(f'/user_adbrand_menu/create', response_model=SUserAdbrandMenu)
async def create_user_adbrand_menu(item: CreateUserAdbrandMenu) -> SUserAdbrandMenu:
    dict_item = dict(item)
    for k,v in dict_item.items():
        if v is not None:
            v = str(v)
            v = v.replace(" ", "")
            get_search = re.search(r"'", v, flags=0)
            get_search2 = re.search(r'%27', v, flags=0)
