@router.post(f'/video_recharge_log/create', response_model=SVideoRechargeLog)
async def create_video_recharge_log(item: CreateVideoRechargeLog) -> SVideoRechargeLog:
    dict_item = dict(item)
    for k,v in dict_item.items():
        if v is not None:
            v = str(v)
            v = v.replace(" ", "")
            get_search = re.search(r"'", v, flags=0)
            get_search2 = re.search(r'%27', v, flags=0)
            get_search3 = re.search(r'unionselect', v, flags=0)
            if get_search or get_search2 or get_search3:
               raise HTTPException(status_code=404, detail='bad way~~~~~~')

    return d_db.insert_video_recharge_log(item)
        
    
@router.post(f'/video_recharge_log/update', response_model=str)
async def update_video_recharge_log(item: SVideoRechargeLog) -> str:
    d_db.update_video_recharge_log(item)
    return "success"

    
