@router.get(f'/video_task_type/filter', response_model=FilterResVideoTaskType)
async def filter_video_task_type(
        id: Optional[str] = None, 
        register_time: Optional[str] = None, 
        title: Optional[str] = None, 
        describe: Optional[str] = None, 
        cover: Optional[str] = None, 
        l_id: Optional[str] = None, 
        l_register_time: Optional[str] = None, 
        l_title: Optional[str] = None, 
        l_describe: Optional[str] = None, 
        l_cover: Optional[str] = None, 
        s_title: Optional[str] = None, 
        s_describe: Optional[str] = None, 
        s_cover: Optional[str] = None,
        order_by: Optional[str] = None,
        page: int = 1, 
        page_size: int = 20) -> FilterResVideoTaskType:

    """
    1. 按照字段查询`?field1=value1&field2=value2`
    2. 按照范围查询，大于某个值`?field=value,`, 表示filed大于value
    3. 按照范围查询，小于某个值`?field=,value`， 表示field小于value
    4. 按照范围查询，范围值`?field=value1,value2`，表示搜索field大于等于value1，小于等于value2
    5. page是页数，第一页为1
    6. page_size为每一页大小， 默认20
    7. 如果是日期，请使用时间戳，十位的时间戳，单位：秒
    8. 所有字符串字段均可搜索，需要在字段前加个前缀`s_`,例如搜索`username`包含`zhang`， 则可以这样`s_username=zhang`写,这里只是一个假设
    9. 字段的多选择（in关系），需要在字段前加前缀`l_`,并且以逗号`,`隔开,例如要找出`id=2`或者`id=3`的样本，可以这样写`?l_id=2,3`
    """
    

    items = dict()
    search_items = dict()
    set_items = dict()

    if id is not None:
        values = id.split(',')
        if len(values) == 1:
            val = values[0]
            items['id'] = int(val)
        else:
            val = values[0]
            if val != '':
                items['id_start'] = int(val)
            
            val = values[1]
            if val != '':
                items['id_end'] = int(val)
        
    if register_time is not None:
        values = register_time.split(',')
        if len(values) == 1:
            val = values[0]
            items['register_time'] = datetime.fromtimestamp(int(val))
        else:
            val = values[0]
            if val != '':
                items['register_time_start'] = datetime.fromtimestamp(int(val))
            
            val = values[1]
            if val != '':
                items['register_time_end'] = datetime.fromtimestamp(int(val))
        
    if title is not None:
        values = title.split(',')
        if len(values) == 1:
            val = values[0]
            items['title'] = val
        else:
            val = values[0]
            if val != '':
                items['title_start'] = val
            
            val = values[1]
            if val != '':
                items['title_end'] = val
        
    if describe is not None:
        values = describe.split(',')
        if len(values) == 1:
            val = values[0]
            items['describe'] = val
        else:
            val = values[0]
            if val != '':
                items['describe_start'] = val
            
            val = values[1]
            if val != '':
                items['describe_end'] = val
        
    if cover is not None:
        values = cover.split(',')
        if len(values) == 1:
            val = values[0]
            items['cover'] = val
        else:
            val = values[0]
            if val != '':
                items['cover_start'] = val
            
            val = values[1]
            if val != '':
                items['cover_end'] = val
        

    if s_title is not None:
        search_items['title'] = '%' + s_title + '%'
        
    if s_describe is not None:
        search_items['describe'] = '%' + s_describe + '%'
        
    if s_cover is not None:
        search_items['cover'] = '%' + s_cover + '%'
        

    if l_id is not None:
        values = l_id.split(',')
        values = [int(val) for val in values]
        set_items['id'] = values
        
    if l_register_time is not None:
        values = l_register_time.split(',')
        values = [datetime.fromtimestamp(int(val)) for val in values]
        set_items['register_time'] = values
        
    if l_title is not None:
        values = l_title.split(',')
        values = [val for val in values]
        set_items['title'] = values
        
    if l_describe is not None:
        values = l_describe.split(',')
        values = [val for val in values]
        set_items['describe'] = values
        
    if l_cover is not None:
        values = l_cover.split(',')
        values = [val for val in values]
        set_items['cover'] = values
            
    
    
    order_items = dict()
    if order_by is not None:
        orders = order_by.split(',')
        for order in orders:
            if order.startswith('-'):
                order_items[order[1:]] = 'desc'
            else:
                order_items[order] = 'asc'
    data = d_db.filter_video_task_type(items, search_items, set_items, order_items, page, page_size)
    c = d_db.filter_count_video_task_type(items, search_items, set_items)
    
    return FilterResVideoTaskType(data=data, total=c)


